const schema = z.object({ comment: z.string().max(500).trim() })

export function useSanitizedForm() {
  const comment = ref('')
  const submit = () => {
    const result = schema.safeParse({ comment: comment.value })
    if (!result.success) return result.error.flatten()
    return result.data // safe to send to API
  }
  return { comment, submit }
}

